    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0xE78632A19003057BULL + 0xD5CE98736D7B2D3FULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseA(pNonce * 0xB0F19BC058DFFB61ULL + 0x805AEAE90D554E5CULL);
