    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xB7B7D410B87CC1DBULL + 0xD1C2F902880C0FA7ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xFA32F6CA9E1C6D7BULL + 0xFD13516CFE9716FAULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0x8203EE0DB8D6F70FULL + 0x96DCE9892CDD00D5ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xCBF4E0BBF740E0DDULL + 0xDE2997BA395EB8F1ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xCBB9C0237908111BULL + 0xF4DD49CD54B5F67BULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0x84F2E869F9D1E2B3ULL + 0xEFD2CC3F9706AB61ULL);
