            //
            aOrbiterE = (((aWandererG + RotL64(aScatter, 57U)) + RotL64(aCarry, 11U)) + 11051089106217163650U) + aOrbiterAssignSaltD[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterG = ((aWandererF + RotL64(aPrevious, 60U)) + RotL64(aCarry, 27U)) + 3656567561067868207U;
