            //
            aOrbiterI = ((aOrbiterI + aOrbiterB) + 12354301178297560488U) + aOrbiterUpdateSaltD[((aIndex + 4U)) & S_SALT1];
            aOrbiterC = (((aOrbiterC ^ aOrbiterI) ^ 2385838478112703058U) ^ aOrbiterUpdateSaltB[(((31U - aIndex) + 10U)) & S_SALT1]) ^ aNonceWordF;
            aOrbiterC = RotL64((aOrbiterC * 14243915785585350121U), 5U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterD) + 8089761110850872213U;
            aOrbiterF = (aOrbiterF ^ aOrbiterH) ^ 4872458171424643032U;
            aOrbiterF = RotL64((aOrbiterF * 3919547954529192055U), 57U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterF) + 15485087940001272090U;
            aOrbiterK = (aOrbiterK ^ aOrbiterG) ^ 3872599055949635389U;
            aOrbiterK = RotL64((aOrbiterK * 14802734999593430845U), 29U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 11287421217345172461U;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 16492795081178269103U;
            aOrbiterD = RotL64((aOrbiterD * 10501743533883408109U), 23U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterA) + 9829183912337843701U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterC) ^ 4984656484346506714U;
