            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 9329800332285681701U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterB) ^ 17920023415610375366U) ^ aNonceWordO;
            aOrbiterA = RotL64((aOrbiterA * 9634392163561349829U), 47U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterH) + 16938818457402363576U;
            aOrbiterG = (aOrbiterG ^ aOrbiterA) ^ 5598072935111494843U;
            aOrbiterG = RotL64((aOrbiterG * 8889944471226378569U), 37U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterJ) + 3190650388191773786U;
