            aOrbiterH = RotL64((aOrbiterH * 1931588890809625729U), 19U);
            //
            aOrbiterF = (((aOrbiterF + aOrbiterI) + 9341272086184037038U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 14U)) & S_SALT1]) + aNonceWordL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterF) ^ 859332492851231137U;
            aOrbiterJ = RotL64((aOrbiterJ * 8665526933279020397U), 51U);
            //
            aIngress = aOrbiterH ^ RotL64(aOrbiterK, 41U);
            aIngress = aIngress + (RotL64(aOrbiterG, 5U) ^ aOrbiterA);
