            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererI = aWandererI + (((RotL64(aIngress, 21U) + aOrbiterF) + RotL64(aOrbiterI, 11U)) + aWandererUpdateSaltE[(((31U - aIndex) + 13U)) & S_SALT1]);
            aWandererC = aWandererC ^ (((RotL64(aCross, 60U) + RotL64(aOrbiterK, 36U)) + aOrbiterB) + aNonceWordD);
            aWandererK = aWandererK + ((((RotL64(aPrevious, 39U) + RotL64(aOrbiterH, 13U)) + aOrbiterK) + RotL64(aCarry, 47U)) + aNonceWordA);
