            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 15234912329206061607U;
            aOrbiterE = (aOrbiterE ^ aOrbiterB) ^ 11574862021832004712U;
            aOrbiterE = RotL64((aOrbiterE * 3284645956192951811U), 3U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterC) + 1370414500463746441U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterA) ^ 601959862262860076U) ^ aOrbiterUpdateSaltF[((aIndex + 28U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 9813614247518813111U), 5U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterJ) + 6801932502657655714U;
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 9665492273241045423U;
            aOrbiterD = RotL64((aOrbiterD * 11358042219543742869U), 19U);
            //
            aOrbiterD = (((aOrbiterD + aOrbiterK) + 15006069914861334781U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 19U)) & S_SALT1]) + aNonceWordP;
            aOrbiterH = (aOrbiterH ^ aOrbiterD) ^ 16015532445670330419U;
            aOrbiterH = RotL64((aOrbiterH * 17335000240010693613U), 35U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterE) + 17032481189738635627U) + aOrbiterUpdateSaltE[((aIndex + 25U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterF) ^ 8594515209188988668U;
            aOrbiterA = RotL64((aOrbiterA * 4259091852288870955U), 39U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterH) + 9968826239266989446U) + aNonceWordM;
